#include <stdio.h>

int majorityElement(int arr[], int n) {
    int candidate = arr[0];
    int count = 1;
    for (int i = 1; i < n; ++i) {
        if (arr[i] == candidate) {
            ++count;
        } else {
            --count;
            if (count == 0) {
                candidate = arr[i];
                count = 1;
            }
        }
    }
    return candidate;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        int arr[n];
        for (int i = 0; i < n; ++i) {
            scanf("%d", &arr[i]);
        }
        printf("%d\n", majorityElement(arr, n));
    }
    return 0;
}

