import sys

def majority_element(arr):
    candidate = arr[0]
    count = 1
    for num in arr[1:]:
        if num == candidate:
            count += 1
        else:
            count -= 1
            if count == 0:
                candidate = num
                count = 1
    return candidate

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        out.append(str(majority_element(arr)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

